        gap: 1vw;
        width: calc(100% + 1vw);
    }

    .index .list ul li {
        background: var(--white);
        border: solid 1px #ddd;
        width: calc(50% - 1vw);
        border-radius: 8px;
        padding: 15px;
        position: relative;
        display: flex;
        justify-content: space-between;
    }

    .index .list ul li .fm {
        width: 30%;
    }

    .index .list ul li .fmn {
        padding-bottom: 144.230769230769%;
        height: 100%;
        background: url("../assets/fm.png");
        background-size: cover;
        position: relative;
    }

    .index .list ul li .fmn .name {
        position: absolute;
        width: 21.5384615385%;
        height: 53.8666666667%;
        left: 10%;
        top: 6.9%;
        display: flex;
        align-items: center;
        justify-content: center;
    }

    .index .list ul li .fmn .name h2 {
        font-weight: 500;
