        width: var(--fs);
    }
    .index .list ul li .other{
        width: calc(70% - 15px);
    }
    .index .list ul li .views {
        display: flex;gap:5px}
    .index .list ul li .other a{
        width: 50%;
    }
    .index .list ul li .other .el-button{
        margin-left: 0;border-radius: 0;
